mapper.insert:
INSERT INTO crm_logs.send_logs_${taskId}
USING crm_logs.send_logs TAGS (#{customerId}, #{taskId}, #{bizType})
VALUES (NOW, #{sendStatus}, #{channel}, #{failReason}, #{templateCode})

mapper.select:
SELECT biz_type AS bizType, channel, COUNT(*) AS totalCount, SUM(CASE WHEN send_status = 'SUCCESS' THEN 1 ELSE 0 END) AS successCount, SUM(CASE WHEN send_status = 'FAIL' THEN 1 ELSE 0 END) AS failCount, SUM(CASE WHEN send_status = 'OPEN' THEN 1 ELSE 0 END) AS openCount FROM crm_logs.send_logs WHERE ts >= TODAY()
AND biz_type = #{bizType}
AND channel = #{channel}
GROUP BY biz_type, channel
